import React, { useState } from 'react';

interface Photo {
  id: number;
  src: string;
  caption: string;
  color: string;
  label: string;
}

const photos: Photo[] = [
  { id: 1, src: '/img/image1.png', caption: 'Ring Ceremony', color: 'from-rose-900 to-red-950', label: 'The Promise' },
  { id: 2, src: '/img/image2.png', caption: 'Mehendi Night', color: 'from-emerald-900 to-green-950', label: 'Henna Night' },
  { id: 3, src: '/img/image3.jpeg', caption: 'Haldi Ceremony', color: 'from-yellow-800 to-amber-950', label: 'Turmeric Glow' },
  { id: 4, src: '/img/image4.jpeg', caption: 'Temple Blessing', color: 'from-orange-900 to-red-950', label: 'Sacred Moments' },
  { id: 5, src: '/img/image5.jpeg', caption: 'Bridal Look', color: 'from-pink-900 to-rose-950', label: 'The Bride' },
];

const PhotoGallery: React.FC = () => {
  const [lightbox, setLightbox] = useState<Photo | null>(null);

  return (
    <section
      style={{
        minHeight: '100vh',
        background: 'linear-gradient(180deg,#050205,#1a0508,#2a0810,#1a0508,#050205)',
        padding: '80px 16px',
      }}
    >
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>
        {/* Grid */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
            gap: 20,
          }}
        >
          {photos.map((photo, idx) => (
            <div
              key={photo.id}
              onClick={() => setLightbox(photo)}
              style={{
                background: `linear-gradient(145deg, ${getColor(photo.color)})`,
                borderRadius: 10,
                overflow: 'hidden',
                cursor: 'pointer',
                boxShadow: '0 10px 30px rgba(0,0,0,.4)',
                aspectRatio: window.innerWidth < 768 ? 'auto' : idx === 0 ? '16/9' : '4/3',
              }}
            >
              <img
                src={photo.src}
                alt={photo.caption}
                style={{
                  width: '100%',
                  height: '100%',
                  maxHeight: window.innerWidth < 768 ? 'none' : '100%',
                  objectFit: window.innerWidth < 768 ? 'contain' : 'cover',
                  display: 'block',
                }}
              />

              {/* Caption */}
              <div style={{ padding: 14 }}>
                <div style={{ color: '#FFD700', fontStyle: 'italic', fontSize: 18 }}>
                  {photo.label}
                </div>
                <div style={{ fontSize: 11, color: '#FFA07A', letterSpacing: '0.2em' }}>
                  {photo.caption.toUpperCase()}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div
          onClick={() => setLightbox(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,.95)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 9999,
          }}
        >
          <div
            style={{
              width: '95vw',
              maxWidth: 900,
              textAlign: 'center',
            }}
          >
            <img
              src={lightbox.src}
              alt={lightbox.caption}
              style={{
                width: '100%',
                maxHeight: '90vh',
                objectFit: 'contain',
                borderRadius: 12,
              }}
            />
            <div style={{ color: '#FFD700', fontSize: 26, marginTop: 12 }}>
              {lightbox.label}
            </div>
            <div style={{ color: '#FFA07A', letterSpacing: '0.2em' }}>
              {lightbox.caption}
            </div>
          </div>
        </div>
      )}
    </section>
  );
};

function getColor(colorClass: string): string {
  const map: Record<string, string> = {
    'from-rose-900 to-red-950': '#4a0d1a, #2d0510',
    'from-emerald-900 to-green-950': '#064a25, #022d10',
    'from-yellow-800 to-amber-950': '#4a3006, #2d1a02',
    'from-orange-900 to-red-950': '#4a1e06, #2d0a02',
    'from-pink-900 to-rose-950': '#4a0d25, #2d0515',
  };
  return map[colorClass] || '#4a0d1a, #2d0510';
}

export default PhotoGallery;
